  1→package gptinclaude
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"strings"
  7→
  8→	"github.com/router-for-me/CLIProxyAPI/v6/internal/thinking"
  9→	"github.com/tidwall/gjson"
 10→)
 11→
 12→type ClientKind string
 13→
 14→const (
 15→	ClientUnknown      ClientKind = "unknown"
 16→	ClientClaudeCLI    ClientKind = "claude-cli"
 17→	ClientClaudeVSCode ClientKind = "claude_vscode"
 18→	ClientCodexVSCode  ClientKind = "codex_exec_vscode"
 19→)
 20→
 21→type headerGetter interface {
 22→	GetHeader(string) string
 23→}
 24→
 25→// DetectClientKind classifies the downstream client from request headers stored
 26→// in context. This keeps client-specific compatibility behavior isolated to the
 27→// Claude -> GPT compatibility path without mutating request payloads.
 28→func DetectClientKind(ctx context.Context) ClientKind {
 29→	if ctx == nil {
 30→		return ClientUnknown
 31→	}
 32→
 33→	getter, _ := ctx.Value("gin").(headerGetter)
 34→	if getter == nil {
 35→		return ClientUnknown
 36→	}
 37→
 38→	userAgent := strings.ToLower(strings.TrimSpace(getter.GetHeader("User-Agent")))
 39→	originator := strings.ToLower(strings.TrimSpace(getter.GetHeader("Originator")))
 40→
 41→	switch {
 42→	case strings.Contains(userAgent, "claude-vscode"):
 43→		return ClientClaudeVSCode
 44→	case strings.HasPrefix(userAgent, "claude-cli/"):
 45→		return ClientClaudeCLI
 46→	case strings.Contains(userAgent, "vscode/"), originator == "codex_exec":
 47→		return ClientCodexVSCode
 48→	default:
 49→		return ClientUnknown
 50→	}
 51→}
 52→
 53→// ShouldEmitSyntheticWebSearchTag limits synthetic Claude-style websearch text
 54→// blocks to the real Claude CLI path. VSCode/Codex clients have their own
 55→// rendering expectations and should not receive the same synthetic text.
 56→func ShouldEmitSyntheticWebSearchTag(kind ClientKind) bool {
 57→	return kind == ClientClaudeCLI
 58→}
 59→
 60→// ShouldSurfaceReasoningSummaryAsThinking controls whether Codex reasoning
 61→// summaries should be exposed as Claude "thinking" blocks. VSCode clients render
 62→// these summaries as if they were live thoughts, which is misleading because the
 63→// summaries usually arrive after the actual search work has already happened.
 64→func ShouldSurfaceReasoningSummaryAsThinking(kind ClientKind) bool {
 65→	switch kind {
 66→	case ClientClaudeCLI, ClientClaudeVSCode, ClientCodexVSCode:
 67→		return false
 68→	default:
 69→		return true
 70→	}
 71→}
 72→
 73→// ShouldEmitVSCodeWebSearchProgress reports whether the client should receive a
 74→// compact progress hint tied to real web_search_call events instead of verbose
 75→// post-hoc reasoning summaries.
 76→func ShouldEmitVSCodeWebSearchProgress(kind ClientKind) bool {
 77→	switch kind {
 78→	case ClientClaudeVSCode, ClientCodexVSCode:
 79→		return true
 80→	default:
 81→		return false
 82→	}
 83→}
 84→
 85→// BuildClaudeCLIToolProgressText returns a short, Codex-like progress update
 86→// for real Claude CLI sessions based on the tool being invoked. Keep this
 87→// factual and category-level rather than echoing raw arguments, so it improves
 88→// perceived liveness without leaking verbose protocol details into the chat.
 89→func BuildClaudeCLIToolProgressText(toolName string) (category string, text string) {
 90→	name := strings.ToLower(strings.TrimSpace(toolName))
 91→	switch name {
 92→	case "grep", "glob":
 93→		return "search", "Searching the codebase."
 94→	case "read":
 95→		return "read", "Reading relevant files."
 96→	case "bash", "shell":
 97→		return "shell", "Running a verification command."
 98→	default:
 99→		return "", ""
100→	}
101→}
102→
103→// ShouldPreEmitBuiltinWebSearchProgress restricts early synthetic progress to
104→// prompts that explicitly ask for a web search. Claude Code often advertises
105→// WebSearch as an available tool even for normal coding tasks, and eagerly
106→// showing "Searching the web." on response.created causes false positives in
107→// the CLI experience.
108→func ShouldPreEmitBuiltinWebSearchProgress(rawJSON []byte) bool {
109→	if !HasBuiltinWebSearch(rawJSON) {
110→		return false
111→	}
112→
113→	return hasExplicitBuiltinWebSearchIntent(extractLatestUserText(rawJSON))
114→}
115→
116→// BuildVSCodeWebSearchProgressThinking renders a short, factual progress message
117→// for VSCode-style clients. Unlike synthetic <tool_call> text, this keeps the
118→// UI concise and avoids leaking implementation details into the chat transcript.
119→func BuildVSCodeWebSearchProgressThinking(action gjson.Result, fallbackQuery string) string {
120→	switch strings.ToLower(strings.TrimSpace(action.Get("type").String())) {
121→	case "search":
122→		query := strings.TrimSpace(action.Get("query").String())
123→		if query == "" {
124→			query = strings.TrimSpace(fallbackQuery)
125→		}
126→		if query != "" {
127→			return "Searching the web for: " + query
128→		}
129→	}
130→
131→	if query := strings.TrimSpace(fallbackQuery); query != "" {
132→		return "Searching the web for: " + query
133→	}
134→	return "Searching the web."
135→}
136→
137→// HasBuiltinWebSearch reports whether the Claude request declared a search tool
138→// that should be routed to Codex built-in web_search on the Claude -> GPT
139→// compatibility path. This includes Anthropic's built-in web_search tool and
140→// Claude Code's generic WebSearch function tool.
141→func HasBuiltinWebSearch(rawJSON []byte) bool {
142→	tools := gjson.GetBytes(rawJSON, "tools")
143→	if !tools.IsArray() {
144→		return false
145→	}
146→
147→	for _, tool := range tools.Array() {
148→		if IsCodexBuiltinWebSearchTool(tool) {
149→			return true
150→		}
151→	}
152→	return false
153→}
154→
155→// IsCodexBuiltinWebSearchTool reports whether a Claude tool declaration should
156→// be translated to the Codex built-in web_search tool.
157→func IsCodexBuiltinWebSearchTool(tool gjson.Result) bool {
158→	if !tool.Exists() {
159→		return false
160→	}
161→
162→	if strings.EqualFold(tool.Get("type").String(), "web_search_20250305") {
163→		return true
164→	}
165→	if strings.EqualFold(tool.Get("name").String(), "web_search") && tool.Get("type").Exists() {
166→		return true
167→	}
168→
169→	if !strings.EqualFold(strings.TrimSpace(tool.Get("name").String()), "WebSearch") {
170→		return false
171→	}
172→
173→	schema := tool.Get("input_schema")
174→	if !schema.Exists() {
175→		return true
176→	}
177→
178→	query := schema.Get("properties.query")
179→	if query.Exists() {
180→		return true
181→	}
182→	if required := schema.Get("required"); required.IsArray() {
183→		for _, item := range required.Array() {
184→			if strings.EqualFold(strings.TrimSpace(item.String()), "query") {
185→				return true
186→			}
187→		}
188→	}
189→	return false
190→}
191→
192→// ClampReasoningEffort caps search-heavy Claude->GPT requests at medium effort so
193→// the model reaches the first search call faster instead of overthinking before
194→// invoking the built-in search tool.
195→func ClampReasoningEffort(effort string, hasBuiltinWebSearch bool) string {
196→	normalized := strings.ToLower(strings.TrimSpace(effort))
197→	if normalized == "" {
198→		normalized = "medium"
